    "example_question_sqls": [
      {
        "id": "01f12868d28d1782b0f3e1f7fd26e5d1",
        "question": [
          "Main user details/filters/identifiers/classifications"
        ],
        "sql": [
          "-- main user filters\r\n",
          "  SELECT\r\n",
          "      dc.RealCID AS CID, -- primary user ID, sometimes referred to as CID or RealCID in other tables\r\n",
          "      dc.GCID, -- secondary user ID\r\n",
          "      DATE_FORMAT(dc.RegisteredReal, 'yyyy-MM-dd') AS RegisteredDate,\r\n",
          "      dc.FirstDepositAmount, -- the amount in dollars of the users first deposit (a key KPI of the business)\r\n",
          "      DATE_FORMAT(dc.FirstDepositDate, 'yyyy-MM-dd') AS FirstDepositDate, -- the date of the users first deposit\r\n",
          "      dc.FTDPlatformID, --The ID relating to the area of the platform the user first deposited to: 4 = ISA/Moneyfarm, 3 = IBAN, 2 = Options, 1 = Trading Platform\r\n",
          "      at.Name as FTDPlatformName, -- The name of the area of the platform the user first deposited to\r\n",
          "      dc.CountryID, -- -- The ID relating to the Country of a user, can then be used to attain their Region too from the lookup table\r\n",
          "      dc1.Name as Country, -- Primary CountryName field of a user\r\n",
          "      dc1.MarketingRegionManualName as Region, -- primary Region field of a user\r\n",
          "      dc.AffiliateID, -- the ID of the affiliate partner that referred/directed the user to signup\r\n",
          "      dc.RegulationID, -- current financial regulatory body ID of the user\r\n",
          "      dr.Name as RegulationName, -- such as FCA or CySec \r\n",
          "      dc.PlayerLevelID, -- the ID relative the the users \"club\" level\r\n",
          "      pl.Name as ClubStatus, --the current club status of a user (can change depending amount the user deposits/equity level of the user)\r\n",
          "      dc.SubChannelID, -- the ID for the subchannel of acquisition\r\n",
          "      dc3.Channel, --the name of the Channel of acquisition\r\n",
          "      dc3.SubChannel, -- the name of the SubCannel of acquisition (in hierarchical order of Channel > SubChannel)   \r\n",
          "      dc.VerificationLevelID, -- the current onboarding verification level of the user depending on KYC completion and other verification tasks (V0 being the lowest level of verified)\r\n",
          "      dc.PlayerStatusID, -- the ID associated with the general current status (for example blocked) of the user\r\n",
          "      ps.Name as PlayerStatus, -- the name associated with the general current status (for example blocked) of the user\r\n",
          "      dc.AccountManagerID, --the ID of the current Account Manager of this user\r\n",
          "      am.FirstName as AccountManagerFirstName,\r\n",
          "      am.LastName as AccountManagerLastName, -- can be concatenated with the First name to get the user's current Account Manager's Full Name\r\n",
          "      dc.GuruStatusID, -- the ID relating to the current Guru level of the user (predominantly in reference to Popular Investors or CopyTraders, this level changes the more \"Copiers\" the user has) \r\n",
          "      gs.GuruStatusName, -- the name relating to the current Guru level of the user (predominantly in reference to Popular Investors or CopyTraders, this level changes the more \"Copiers\" the user has). You can then see their number of copiers via the dc.NumOfCopiers field.\r\n",
          "      dc.IsValidCustomer, -- a boolean value of whether the user is a valid customer or not, should always IsValidCustomer = 1 when analysing regular clients unless otherwise stated\r\n",
          "      dc.Gender, -- user's Gender (F, M, U or NULL)\r\n",
          "      dc.BirthDate\r\n",
          "  FROM main.pii_data.gold_sql_dp_prod_we_dwh_dbo_dim_customer dc\r\n",
          "  JOIN main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_country dc1 ON dc.CountryID = dc1.CountryID\r\n",
          "  JOIN main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_channel dc3 ON dc.SubChannelID = dc3.SubChannelID\r\n",
          "  JOIN main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_gurustatus gs ON gs.GuruStatusID = dc.GuruStatusID\r\n",
          "  JOIN main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_playerlevel pl ON pl.PlayerLevelID = dc.PlayerLevelID\r\n",
          "  JOIN main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_playerstatus ps ON ps.PlayerStatusID = dc.PlayerStatusID\r\n",
          "  JOIN main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_manager am ON am.ManagerID = dc.AccountManagerID\r\n",
          "  JOIN main.dwh.gold_sql_dp_prod_we_dwh_dbo_dim_regulation dr ON dr.ID = dc.RegulationID\r\n",
          "  JOIN main.pii_data.gold_sql_dp_prod_we_dwh_dbo_dim_affiliate da ON da.AffiliateID = dc.AffiliateID\r\n",
          "  JOIN main.bi_db.bronze_moneybusdb_dictionary_accounttypes at ON at.ID = dc.FTDPlatformID\r\n",
          "  WHERE IsValidCustomer = 1 -- a boolean value of whether the user is a valid customer or not, should always IsValidCustomer = 1 when analysing regular clients unless otherwise stated."
        ],
        "usage_guidance": [
          "Use this as a base/example of all frequently used and key user details/filters/identifiers/classifications. This should help identify relevant joins and relationships when asked to return data for a specific set of users with certain characteristics or details. This can also identify when a user Registered, First Deposited and how much their First Deposit was - this in turn can help answer questions like \"how many user Registered on a certain date?\" or \"how many users First Deposited on a certain date?\""
        ]
      }
    ],
